"""
This is the main module to launch the program
"""

from board import Board, Piece
from player import Player
from move import Move

class Game:
    def __init__(self):
        self.board = Board()
        self.players = [Player(color="white"), Player(color="black")]
        self.current_player_index = 0

    def run(self):
        while not self.is_game_over():
            self.print_board()
            player = self.get_current_player()
            move_input = input(f"{player.color.capitalize()} player, enter your move (e.g., a2-a4): ")
            try:
                move = Move.from_notation(move_input)
                if move.is_valid(self.board, self.players[self.current_player_index].pieces):
                    self.make_move(move)
                    self.switch_player()
                else:
                    print("Invalid move. Please try again.")
            except ValueError:
                print("Invalid move notation. Please try again.")

    def is_game_over(self):
        # Check for win or draw conditions
        return False

    def get_current_player(self):
        return self.players[self.current_player_index]

    def make_move(self, move):
        move.execute(self.board)

    def switch_player(self):
        self.current_player_index = 1 - self.current_player_index

    def print_board(self):
        print(self.board)

if __name__ == "__main__":
    game = Game()
    game.run()
```

