"""
Represents the 8x8 board and handles its state.
"""

import numpy as np

class Board:
    def __init__(self):
        self.grid = np.array([
            [Piece(color="black", is_king=False) if (i + j) % 2 == 1 else None for j in range(8)]
            for i in range(8)
        ])
        # Initialize pieces
        for row in range(3, 5):
            for col in range(8):
                self.grid[row, col] = Piece(color="black", is_king=False)

    def __str__(self):
        return "\n".join([" ".join([piece.symbol if piece else '.' for piece in row]) for row in self.grid])

class Piece:
    def __init__(self, color, is_king):
        self.color = color
        self.is_king = is_king

    @property
    def symbol(self):
        return "K" if self.is_king else self.color[0]

